105	function RevealItem({ children, delay = 0 }: { children: React.ReactNode; delay?: number }) {
106	  const ref = useRef<HTMLDivElement>(null);
107	  const [visible, setVisible] = useState(false);
108	  const delayClass = delay === 240 ? "delay-[240ms]" : delay === 160 ? "delay-[160ms]" : delay === 80 ? "delay-[80ms]" : "delay-0";
109	
110	  useEffect(() => {
111	    const el = ref.current;
112	    if (!el) return;
113	    const obs = new IntersectionObserver(
114	      ([entry]) => {
115	        if (entry.isIntersecting) {
116	          setVisible(true);
117	          obs.disconnect();
118	        }
119	      },
120	      { threshold: 0.1, rootMargin: "0px 0px -60px 0px" }
121	    );
122	    obs.observe(el);
123	    return () => obs.disconnect();
124	  }, []);
125	
126	  return (
127	    <div
128	      ref={ref}
129	      className={`transition-[opacity,transform] duration-600 ease-[cubic-bezier(0.16,1,0.3,1)] ${delayClass} ${visible ? "translate-y-0 opacity-100" : "translate-y-5 opacity-0"}`}
130	    >
