                      >
                        {plan.cta}
                        <ArrowRightIcon className="size-3.5" />
                      </Link>
                    </div>
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          {tableData.map((group) => (
            <tbody key={group.title}>
              <tr>
